#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int s[2],f,v;
    int sz,tag;
    void init(int _f,int _v){
        f=_f,v=_v;
        sz=1,tag=0;
    }
}t[N];

int n,m;
int root,tot;

void pushup(int x){
    if(x) t[x].sz=t[t[x].s[0]].sz+1+t[t[x].s[1]].sz;
}

void pushdown(int x){
    if(t[x].tag){
        if(t[x].s[0]){
            t[t[x].s[0]].tag^=1;
            swap(t[t[x].s[0]].s[0],t[t[x].s[0]].s[1]);
        }
        if(t[x].s[1]){
            t[t[x].s[1]].tag^=1;
            swap(t[t[x].s[1]].s[0],t[t[x].s[1]].s[1]);
        }
        t[x].tag=0;
    }
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(t[y].s[1]==x);
    if(z) t[z].s[t[z].s[1]==y]=x;
    t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x,int k){
    while(t[x].f!=k){
        int y=t[x].f,z=t[y].f;
        if(z!=k)
            if((x==t[y].s[1])==(y==t[z].s[1])) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
    if(!k) root=x;
}

int get_k(int k){
    int x=root;
    while(x){
        pushdown(x);
        if(t[t[x].s[0]].sz>=k) x=t[x].s[0];
        else if(t[t[x].s[0]].sz+1==k) return x;
        else k-=t[t[x].s[0]].sz+1,x=t[x].s[1];
    }
    return -1;
}

void Insert(int v){
    int u=root,p=0;
    while(u)
        p=u,u=t[u].s[v>t[u].v]; // 一般要加一个 pushdown
    u=++tot;
    t[u].init(p,v);
    if(p) t[p].s[v>t[p].v]=u;
    Splay(u,0);
    // pushup 直接在 Splay 中实现
}

void output(int x){
    if(!x) return;
    pushdown(x);
    output(t[x].s[0]);
    if(0<t[x].v && t[x].v<=n) printf("%d ",t[x].v);
    output(t[x].s[1]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<=n+1;i++)
        Insert(i);
    // 添加哨兵节点 0,n+1 避免边界情况
    while(m--){
        int l,r;
        scanf("%d%d",&l,&r);
        l=get_k(l),r=get_k(r+2); // 要算上哨兵节点 0
        Splay(l,0),Splay(r,l); // 一般要先将所有祖先节点 pushdown，但这在查询时已经做完了
        t[t[r].s[0]].tag^=1;
        swap(t[t[r].s[0]].s[0],t[t[r].s[0]].s[1]);
    }
    output(root);
    return 0;
}
